import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, HelpCircle, LayoutDashboard, Users, BarChart3
} from 'lucide-react';

const Login = () => {
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [userRequests, setUserRequests] = useState([]); 
  const [allRequests, setAllRequests] = useState([]); 
  const [allUsers, setAllUsers] = useState([]); 
  const [selectedFileName, setSelectedFileName] = useState(""); 

  // --- DATA LOADING ---
  const loadAdminDashboard = async () => {
    try {
      console.log("Fetching Admin Data...");
      const [uRes, rRes] = await Promise.all([
        axios.get('http://localhost:5000/api/users/all'),
        axios.get('http://localhost:5000/api/requests/all')
      ]);
      setAllUsers(uRes.data);
      setAllRequests(rRes.data);
      console.log("Admin Data Loaded:", uRes.data.length, "users", rRes.data.length, "apps");
    } catch (err) {
      console.error("Admin Load Error:", err);
    }
  };

  useEffect(() => {
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('userRole');
    if (token) {
      if (role === 'admin') {
        setView('admin-dashboard');
        loadAdminDashboard();
      } else {
        setView('dashboard');
        axios.get(`http://localhost:5000/api/requests/user/${localStorage.getItem('userId')}`)
          .then(res => setUserRequests(res.data));
      }
    }
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    const mode = view === 'admin-login' ? 'login' : (view === 'register' ? 'register' : 'login');
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      const user = res.data.user;
      
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('userRole', user.role);
      localStorage.setItem('userId', user._id);
      localStorage.setItem('userName', user.name);

      if (user.role === 'admin') {
        setView('admin-dashboard');
        await loadAdminDashboard();
      } else {
        setView('dashboard');
        window.location.reload(); 
      }
    } catch (err) { alert("Login Failed"); }
  };

  const updateStatus = async (id, status) => {
    await axios.put(`http://localhost:5000/api/requests/status/${id}`, { status });
    loadAdminDashboard(); // Refresh
  };

  const handleNativeUpload = async () => {
    const [fileHandle] = await window.showOpenFilePicker();
    const file = await fileHandle.getFile();
    setSelectedFileName(file.name);
  };

  const handleCredentialSubmit = async (e) => {
    e.preventDefault();
    const body = {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
      documentUrl: selectedFileName || "doc.pdf"
    };
    await axios.post('http://localhost:5000/api/requests/submit', body);
    setShowModal(false);
    window.location.reload();
  };

  // --- ADMIN VIEW ---
  if (view === 'admin-dashboard') {
    return (
      <div className="min-h-screen bg-slate-950 text-white flex flex-col">
        <nav className="p-6 border-b border-slate-900 flex justify-between bg-black/40">
          <h1 className="text-xl font-black text-blue-500 italic uppercase">Admin Control</h1>
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 font-bold">Logout</button>
        </nav>
        <main className="p-10 max-w-7xl mx-auto w-full">
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-12">
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800">
                <p className="text-slate-500 text-[10px] font-black uppercase">Registered Users</p>
                <h4 className="text-5xl font-black text-white">{allUsers.length}</h4>
              </div>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 border-l-4 border-l-yellow-500">
                <p className="text-slate-500 text-[10px] font-black uppercase">Service Requests</p>
                <h4 className="text-5xl font-black text-yellow-500">{allRequests.length}</h4>
              </div>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 border-l-4 border-l-green-500">
                <p className="text-slate-500 text-[10px] font-black uppercase">Approved Apps</p>
                <h4 className="text-5xl font-black text-green-500">{allRequests.filter(r => r.status === 'Approved').length}</h4>
              </div>
           </div>

           <div className="bg-slate-900 rounded-[2rem] border border-slate-800 overflow-hidden">
              <table className="w-full text-left">
                <thead className="bg-black/20 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b border-slate-800">
                  <tr><th className="p-6">Provider</th><th className="p-6">Type</th><th className="p-6">Status</th><th className="p-6">Action</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {allRequests.map((req) => (
                    <tr key={req._id} className="hover:bg-blue-600/5 transition">
                      <td className="p-6 font-black text-xs">{req.userName}</td>
                      <td className="p-6 text-slate-400 text-xs italic">{req.type}</td>
                      <td className="p-6">
                        <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase ${req.status === 'Approved' ? 'text-green-500 bg-green-500/10' : 'text-yellow-500 bg-yellow-500/10'}`}>
                          {req.status}
                        </span>
                      </td>
                      <td className="p-6 space-x-2">
                        <button onClick={() => updateStatus(req._id, 'Approved')} className="bg-green-600 px-3 py-1 rounded text-[9px] font-black uppercase">Approve</button>
                        <button onClick={() => updateStatus(req._id, 'Rejected')} className="bg-red-600/20 px-3 py-1 rounded text-[9px] font-black uppercase border border-red-500/20 text-red-500">Reject</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
           </div>
        </main>
      </div>
    );
  }

  // --- LANDING / USER VIEW ---
  if (view === 'landing' || view === 'login' || view === 'register' || view === 'admin-login') {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6">
        {view === 'landing' ? (
          <div className="max-w-4xl w-full text-center">
            <h1 className="text-5xl font-black text-slate-900 mb-12 italic uppercase">QUAD SOLUTIONS</h1>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div onClick={() => setView('register')} className="bg-white p-10 rounded-[2.5rem] shadow-xl cursor-pointer hover:border-blue-600 border-2 border-transparent transition text-left">
                 <UserPlus className="text-blue-600 mb-4" size={32}/>
                 <h2 className="text-2xl font-black">New Providers</h2>
                 <p className="text-blue-600 font-bold mt-2">Get Started <ArrowRight className="inline" size={16}/></p>
              </div>
              <div onClick={() => setView('login')} className="bg-slate-900 text-white p-10 rounded-[2.5rem] shadow-xl cursor-pointer hover:border-blue-400 border-2 border-transparent transition text-left">
                 <LogIn className="text-blue-400 mb-4" size={32}/>
                 <h2 className="text-2xl font-black">Existing Clients</h2>
                 <p className="text-blue-400 font-bold mt-2">Sign In <ArrowRight className="inline" size={16}/></p>
              </div>
            </div>
            <footer className="mt-20">
                <button onClick={() => setView('admin-login')} className="bg-white border px-6 py-2 rounded-full text-[10px] font-black uppercase text-slate-300 hover:text-blue-600 transition">
                   <ShieldCheck className="inline mr-2" size={14}/> Internal Admin Access
                </button>
            </footer>
          </div>
        ) : (
          <div className="w-full max-w-md bg-white p-10 rounded-[2.5rem] shadow-2xl relative">
            <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 font-bold">Back</button>
            <h2 className="text-3xl font-black mb-6 italic uppercase">{view.replace('-', ' ')}</h2>
            <form onSubmit={handleAuth} className="space-y-4">
              {view === 'register' && <input type="text" placeholder="Name" className="w-full p-4 bg-slate-50 rounded-xl font-bold border-none" onChange={e => setFormData({...formData, name: e.target.value})} />}
              <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 rounded-xl font-bold border-none" onChange={e => setFormData({...formData, email: e.target.value})} />
              <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-xl font-bold border-none" onChange={e => setFormData({...formData, password: e.target.value})} />
              <button className="w-full bg-blue-600 text-white py-4 rounded-xl font-black">Continue</button>
            </form>
          </div>
        )}
      </div>
    );
  }

  // User Dashboard
  return (
    <div className="min-h-screen bg-slate-50">
      <nav className="bg-white p-4 shadow-sm flex justify-between">
        <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
        <div className="flex gap-4">
           <button onClick={() => setActiveTab('services')} className={`px-4 py-1 rounded-lg text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>Services</button>
           <button onClick={() => setActiveTab('tracking')} className={`px-4 py-1 rounded-lg text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white' : 'text-slate-400'}`}>Status</button>
           <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500"><LogOut size={20}/></button>
        </div>
      </nav>

      <main className="p-10 max-w-5xl mx-auto">
        {activeTab === 'services' ? (
          <div>
            <h2 className="text-3xl font-black mb-8">Services</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map(t => (
                <div key={t} className="bg-white p-8 rounded-3xl shadow-sm border">
                   <h3 className="text-lg font-bold mb-4">{t}</h3>
                   <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-2 rounded-xl text-[10px] font-black uppercase">Apply Now</button>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div>
            <h2 className="text-3xl font-black mb-8">History</h2>
            {userRequests.map((r, i) => (
              <div key={i} className="bg-white p-6 rounded-3xl border mb-4 flex justify-between items-center">
                 <div className="font-bold">{r.type}</div>
                 <div className="bg-blue-100 text-blue-600 px-4 py-1 rounded-lg text-[10px] font-black uppercase">{r.status}</div>
              </div>
            ))}
          </div>
        )}
      </main>

      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10">
            <h2 className="text-2xl font-black mb-6 text-blue-600">New Application</h2>
            <form onSubmit={handleCredentialSubmit} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-xl font-bold"><option>Medical License</option><option>Insurance Enrollment</option></select>
              <input type="text" placeholder="License ID" className="w-full p-4 bg-slate-50 rounded-xl font-bold" required />
              <div onClick={handleNativeUpload} className="p-8 bg-blue-50 border-2 border-dashed rounded-xl cursor-pointer text-center">
                <Upload className="mx-auto text-blue-400 mb-2"/>
                <p className="text-[10px] font-black uppercase text-blue-600">{selectedFileName || "Select Document"}</p>
              </div>
              <button className="w-full bg-blue-600 text-white py-4 rounded-xl font-black">Submit</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full mt-2 text-slate-400 font-bold">Cancel</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
